import os
import secrets
import hashlib
import time
from flask import Flask, request, jsonify, render_template_string
from flask_mail import Mail, Message
from datetime import datetime, timedelta
import sqlite3
import pyotp
import qrcode
import io
import base64

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your-secret-key-here')
app.config['MAIL_SERVER'] = os.environ.get('MAIL_SERVER', 'smtp.gmail.com')
app.config['MAIL_PORT'] = int(os.environ.get('MAIL_PORT', 587))
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = os.environ.get('MAIL_USERNAME')
app.config['MAIL_PASSWORD'] = os.environ.get('MAIL_PASSWORD')
app.config['MAIL_DEFAULT_SENDER'] = os.environ.get('MAIL_DEFAULT_SENDER')

mail = Mail(app)

DATABASE = 'mfa_system.db'

def get_db():
    db = sqlite3.connect(DATABASE)
    db.row_factory = sqlite3.Row
    return db

def init_db():
    db = get_db()
    db.execute('''
        CREATE TABLE IF NOT EXISTS users (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            email TEXT UNIQUE NOT NULL,
            password_hash TEXT NOT NULL,
            mfa_enabled INTEGER DEFAULT 0,
            mfa_secret TEXT,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
        )
    ''')
    db.execute('''
        CREATE TABLE IF NOT EXISTS mfa_reset_tokens (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            token TEXT UNIQUE NOT NULL,
            expires_at TIMESTAMP NOT NULL,
            used INTEGER DEFAULT 0,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users (id)
        )
    ''')
    db.execute('''
        CREATE TABLE IF NOT EXISTS sessions (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL,
            session_token TEXT UNIQUE NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
            FOREIGN KEY (user_id) REFERENCES users (id)
        )
    ''')
    db.commit()
    db.close()

init_db()

def hash_password(password):
    return hashlib.sha256(password.encode()).hexdigest()

def generate_reset_token():
    return secrets.token_urlsafe(32)

def send_reset_email(email, reset_token):
    reset_link = f"{request.url_root}verify-mfa-reset?token={reset_token}"
    
    msg = Message(
        subject="MFA Reset Request",
        recipients=[email],
        body=f"""
        You have requested to reset your Multi-Factor Authentication (MFA) settings.
        
        Click the link below to complete the MFA reset:
        {reset_link}
        
        This link will expire in 1 hour.
        
        If you did not request this reset, please ignore this email.
        """
    )
    
    try:
        mail.send(msg)
        return True
    except Exception as e:
        print(f"Error sending email: {e}")
        return False

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400
    
    db = get_db()
    try:
        password_hash = hash_password(password)
        db.execute('INSERT INTO users (email, password_hash) VALUES (?, ?)', 
                   (email, password_hash))
        db.commit()
        return jsonify({'message': 'User registered successfully'}), 201
    except sqlite3.IntegrityError:
        return jsonify({'error': 'Email already registered'}), 400
    finally:
        db.close()

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    mfa_code = data.get('mfa_code')
    
    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400
    
    db = get_db()
    user = db.execute('SELECT * FROM users WHERE email = ?', (email,)).fetchone()
    
    if not user:
        db.close()
        return jsonify({'error': 'Invalid credentials'}), 401
    
    password_hash = hash_password(password)
    if user['password_hash'] != password_hash:
        db.close()
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user['mfa_enabled']:
        if not mfa_code:
            db.close()
            return jsonify({'error': 'MFA code required', 'mfa_required': True}), 401
        
        totp = pyotp.TOTP(user['mfa_secret'])
        if not totp.verify(mfa_code, valid_window=1):
            db.close()
            return jsonify({'error': 'Invalid MFA code'}), 401
    
    session_token = secrets.token_urlsafe(32)
    db.execute('INSERT INTO sessions (user_id, session_token) VALUES (?, ?)',
               (user['id'], session_token))
    db.commit()
    db.close()
    
    return jsonify({
        'message': 'Login successful',
        'session_token': session_token,
        'mfa_enabled': bool(user['mfa_enabled'])
    }), 200

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    data = request.get_json()
    session_token = data.get('session_token')
    
    if not session_token:
        return jsonify({'error': 'Session token required'}), 401
    
    db = get_db()
    session = db.execute('SELECT * FROM sessions WHERE session_token = ?', 
                         (session_token,)).fetchone()
    
    if not session:
        db.close()
        return jsonify({'error': 'Invalid session'}), 401
    
    user = db.execute('SELECT * FROM users WHERE id = ?', 
                      (session['user_id'],)).fetchone()
    
    if user['mfa_enabled']:
        db.close()
        return jsonify({'error': 'MFA already enabled'}), 400
    
    secret = pyotp.random_base32()
    
    db.execute('UPDATE users SET mfa_secret = ? WHERE id = ?',
               (secret, user['id']))
    db.commit()
    
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(user['email'], issuer_name="MFA System")
    
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(provisioning_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    
    buffered = io.BytesIO()
    img.save(buffered, format="PNG")
    qr_code_base64 = base64.b64encode(buffered.getvalue()).decode()
    
    db.close()
    
    return jsonify({
        'message': 'MFA setup initiated',
        'secret': secret,
        'qr_code': qr_code_base64,
        'provisioning_uri': provisioning_uri
    }), 200

@app.route('/confirm-mfa', methods=['POST'])
def confirm_mfa():
    data = request.get_json()
    session_token = data.get('session_token')
    mfa_code = data.get('mfa_code')
    
    if not session_token or not mfa_code:
        return jsonify({'error': 'Session token and MFA code required'}), 400
    
    db = get_db()
    session = db.execute('SELECT * FROM sessions WHERE session_token = ?',
                         (session_token,)).fetchone()
    
    if not session:
        db.close()
        return jsonify({'error': 'Invalid session'}), 401
    
    user = db.execute('SELECT * FROM users WHERE id = ?',
                      (session['user_id'],)).fetchone()
    
    if not user['mfa_secret']:
        db.close()
        return jsonify({'error': 'MFA not initiated'}), 400
    
    totp = pyotp.TOTP(user['mfa_secret'])
    if not totp.verify(mfa_code, valid_window=1):
        db.close()
        return jsonify({'error': 'Invalid MFA code'}), 401
    
    db.execute('UPDATE users SET mfa_enabled = 1 WHERE id = ?', (user['id'],))
    db.commit()
    db.close()
    
    return jsonify({'message': 'MFA enabled successfully'}), 200

