@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email required'}), 400
    
    db = get_db()
    user = db.execute('SELECT * FROM users WHERE email = ?', (email,)).fetchone()
    
    if not user:
        db.close()
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200
    
    if not user['mfa_enabled']:
        db.close()
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200
    
    reset_token = generate_reset_token()
    expires_at = datetime.now() + timedelta(hours=1)
    
    db.execute('INSERT INTO mfa_reset_tokens (user_id, token, expires_at) VALUES (?, ?, ?)',
               (user['id'], reset_token, expires_at))
    db.commit()
    db.close()
    
    send_reset_email(email, reset_token)
    
    return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200

@app.route('/verify-mfa-reset', methods=['GET'])
def verify_mfa_reset():
    token = request.args.get('token')
    
    if not token:
        return jsonify({'error': 'Token required'}), 400
    
    db = get_db()
    reset_request = db.execute(
        'SELECT * FROM mfa_reset_tokens WHERE token = ? AND used = 0',
        (token,)
    ).fetchone()
    
    if not reset_request:
        db.close()
        return jsonify({'error': 'Invalid or already used token'}), 400
    
    expires_at = datetime.fromisoformat(reset_request['expires_at'])
    if datetime.now() > expires_at:
        db.close()
        return jsonify({'error': 'Token expired'}), 400
    
    db.execute('UPDATE users SET mfa_enabled = 0, mfa_secret = NULL WHERE id = ?',
               (reset_request['user_id'],))
    db.execute('UPDATE mfa_reset_tokens SET used = 1 WHERE id = ?',
               (reset_request['id'],))
    db.commit()
    
    user = db.execute('SELECT email FROM users WHERE id = ?',
                      (reset_request['user_id'],)).fetchone()
    db.close()
    
    return jsonify({
        'message': 'MFA has been reset successfully. You can now log in with just your password.',
        'email': user['email']
    }), 200

@app.route('/mfa-status', methods=['GET'])
def mfa_status():
    session_token = request.headers.get('Authorization')
    
    if not session_token:
        return jsonify({'error': 'Session token required'}), 401
    
    db = get_db()
    session = db.execute('SELECT * FROM sessions WHERE session_token = ?',
                         (session_token,)).fetchone()
    
    if not session:
        db.close()
        return jsonify({'error': 'Invalid session'}), 401
    
    user = db.execute('SELECT email, mfa_enabled FROM users WHERE id = ?',
                      (session['user_id'],)).fetchone()
    db.close()
    
    return jsonify({
        'email': user['email'],
        'mfa_enabled': bool(user['mfa_enabled'])
    }), 200

